import{_ as e,o as t,c as n,ag as s}from"./chunks/framework.BY_YGHoI.js";const h=JSON.parse('{"title":"I/O","description":"","frontmatter":{},"headers":[],"relativePath":"reference/io.md","filePath":"reference/io.md"}'),o={name:"reference/io.md"};function p(d,a,i,c,l,r){return t(),n("div",null,[...a[0]||(a[0]=[s('<h1 id="i-o" tabindex="-1">I/O <a class="header-anchor" href="#i-o" aria-label="Permalink to &quot;I/O&quot;">​</a></h1><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><h3 id="print-value" tabindex="-1"><code>print(value)</code> <a class="header-anchor" href="#print-value" aria-label="Permalink to &quot;`print(value)`&quot;">​</a></h3><p>Writes a value to stdout followed by a newline. Accepts any type.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>print(&quot;Hello&quot;);       # Hello</span></span>\n<span class="line"><span>print(42);            # 42</span></span>\n<span class="line"><span>print(3.14);          # 3.14</span></span>\n<span class="line"><span>print(true);          # true</span></span>\n<span class="line"><span>print([1, 2, 3]);     # [1, 2, 3]</span></span></code></pre></div><p>String coercion: when the left operand of <code>+</code> is <code>txt</code>, the right operand is automatically converted:</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>print(&quot;Score: &quot; + 100);     # Score: 100</span></span>\n<span class="line"><span>print(&quot;Pi ≈ &quot; + 3.14);     # Pi ≈ 3.14</span></span>\n<span class="line"><span>print(&quot;Done: &quot; + true);     # Done: true</span></span></code></pre></div><h2 id="input" tabindex="-1">Input <a class="header-anchor" href="#input" aria-label="Permalink to &quot;Input&quot;">​</a></h2><h3 id="read-→-txt" tabindex="-1"><code>read()</code> → <code>txt</code> <a class="header-anchor" href="#read-→-txt" aria-label="Permalink to &quot;`read()` → `txt`&quot;">​</a></h3><p>Reads a line from stdin, trims whitespace, returns as <code>txt</code>.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>txt name = read();</span></span></code></pre></div><h3 id="read-txt-prompt-→-txt" tabindex="-1"><code>read(txt prompt)</code> → <code>txt</code> <a class="header-anchor" href="#read-txt-prompt-→-txt" aria-label="Permalink to &quot;`read(txt prompt)` → `txt`&quot;">​</a></h3><p>Prints the prompt (no newline) then reads a line.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>txt name = read(&quot;Enter your name: &quot;);</span></span></code></pre></div><h3 id="read-int-read-int-txt-prompt-→-int" tabindex="-1"><code>read_int()</code> / <code>read_int(txt prompt)</code> → <code>int</code> <a class="header-anchor" href="#read-int-read-int-txt-prompt-→-int" aria-label="Permalink to &quot;`read_int()` / `read_int(txt prompt)` → `int`&quot;">​</a></h3><p>Reads and parses input as <code>int</code>. Raises a runtime error if the input is not a valid integer.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>int n = read_int(&quot;Enter a number: &quot;);</span></span></code></pre></div><h3 id="read-dec-read-dec-txt-prompt-→-dec" tabindex="-1"><code>read_dec()</code> / <code>read_dec(txt prompt)</code> → <code>dec</code> <a class="header-anchor" href="#read-dec-read-dec-txt-prompt-→-dec" aria-label="Permalink to &quot;`read_dec()` / `read_dec(txt prompt)` → `dec`&quot;">​</a></h3><p>Reads and parses input as <code>dec</code>. Raises a runtime error if the input is not a valid decimal.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dec x = read_dec(&quot;Enter a decimal: &quot;);</span></span></code></pre></div><h2 id="type-conversion" tabindex="-1">Type conversion <a class="header-anchor" href="#type-conversion" aria-label="Permalink to &quot;Type conversion&quot;">​</a></h2><p>Convert between types explicitly with cast functions:</p><table tabindex="0"><thead><tr><th>Call</th><th>Input types</th><th>Output</th><th>Notes</th></tr></thead><tbody><tr><td><code>int(x)</code></td><td><code>dec</code>, <code>txt</code>, <code>int</code></td><td><code>int</code></td><td><code>dec</code> truncates toward zero</td></tr><tr><td><code>dec(x)</code></td><td><code>int</code>, <code>txt</code>, <code>dec</code></td><td><code>dec</code></td><td></td></tr><tr><td><code>txt(x)</code></td><td><code>int</code>, <code>dec</code>, <code>bool</code></td><td><code>txt</code></td><td>Formats the value as a string</td></tr></tbody></table><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>int age   = int(read(&quot;Age: &quot;));        # parse user input</span></span>\n<span class="line"><span>dec ratio = dec(3);                    # 3.0</span></span>\n<span class="line"><span>txt label = txt(age + 1);             # number to string</span></span>\n<span class="line"><span>int trunc = int(9.9);                  # 9 (truncated)</span></span></code></pre></div><h2 id="full-example" tabindex="-1">Full example <a class="header-anchor" href="#full-example" aria-label="Permalink to &quot;Full example&quot;">​</a></h2><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main() {</span></span>\n<span class="line"><span>    txt name = read(&quot;What is your name? &quot;);</span></span>\n<span class="line"><span>    print(&quot;Hello, &quot; + name);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    int age = int(read(&quot;Your age: &quot;));</span></span>\n<span class="line"><span>    print(&quot;Next year you will be &quot; + (age + 1));</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    print(&quot;Press Enter to continue...&quot;);</span></span>\n<span class="line"><span>    read();</span></span>\n<span class="line"><span>    print(&quot;Done!&quot;);</span></span>\n<span class="line"><span>}</span></span></code></pre></div>',26)])])}const m=e(o,[["render",p]]);export{h as __pageData,m as default};
